const items = $input.all();

function num(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

// Small modifier from the day's email activity — context, not the primary driver.
function emailModifier(flag, sentiment) {
  const f = String(flag || '').toLowerCase();
  let m = 0;
  if (f === 'high') m += 30;
  else if (f === 'medium') m += 15;

  const s = String(sentiment || '').toLowerCase();
  if (s.includes('negative')) m += 10;

  return m;
}

const ranked = items.map(item => {
  const j = item.json;

  const renewalProximity = num(j.renewal_proximity_score);
  const healthRisk = num(j.health_risk_score);
  const escalation = num(j.escalation_score);
  const expansion = num(j.expansion_score);
  const arr = num(j.arr);
  const emailMod = emailModifier(j.email_urgency_flag, j.email_sentiment);

  // Weighted by stated priority: renewal proximity > health/risk tier >
  // open escalations > expansion signal. Email activity is a light modifier.
  const overall_priority_score =
    (renewalProximity * 5) +
    (healthRisk * 3) +
    (escalation * 2) +
    (expansion * 1) +
    emailMod;

  return {
    json: {
      ...j,
      overall_priority_score,
    }
  };
});

ranked.sort((a, b) => {
  const sa = num(a.json.overall_priority_score);
  const sb = num(b.json.overall_priority_score);
  if (sb !== sa) return sb - sa;

  const ta = num(a.json.arr);
  const tb = num(b.json.arr);
  return tb - ta;
});

return ranked.slice(0, 5).map((item, index) => ({
  json: {
    ...item.json,
    priority_rank: index + 1,
    run_date: item.json.run_date || new Date().toISOString().slice(0, 10),
  }
}));

const items = $input.all();
const source = $('Rank Top 5 Accounts').all();

function extractText(j) {
  return j.raw_ai_text
    ?? j.output?.[0]?.content?.[0]?.text
    ?? j.output?.content?.[0]?.text
    ?? j.output_text
    ?? '';
}

function parseJsonFromText(text) {
  if (!text) return {};
  const s = String(text).trim();
  if (!s) return {};
  try { return JSON.parse(s); } catch {}
  const arrayMatch = s.match(/\[[\s\S]*\]/);
  if (arrayMatch) {
    try { return JSON.parse(arrayMatch[0]); } catch {}
  }
  const objMatch = s.match(/\{[\s\S]*\}/);
  if (objMatch) {
    try { return JSON.parse(objMatch[0]); } catch {}
  }
  return {};
}

function first(v, fallback = '') {
  return v === undefined || v === null || String(v).trim() === '' ? fallback : v;
}

// The AI node's own output replaces each item's json — it does not carry
// forward company_name/company_id/email_sentiment/overall_priority_score
// from before the AI call. Pull those back in from Rank Top 5 Accounts by
// index (same pattern Parse Email Analysis uses for the other AI node).
return items.map((item, i) => {
  const j = item.json;
  const base = source[i] ? source[i].json : {};

  const raw = extractText(j);
  const parsed = parseJsonFromText(raw);
  const entry = Array.isArray(parsed) ? (parsed[0] || {}) : parsed;

  return {
    json: {
      ...base,
      company_name: first(base.company_name),
      company_id: first(base.company_id),
      email_sentiment: first(base.email_sentiment),
      overall_priority_score: first(base.overall_priority_score),
      priority_rank: first(base.priority_rank, entry.rank),
      parsed_priority: first(entry.priority ?? entry.sentiment ?? entry.urgency_flag),
      parsed_reason: first(entry.why_today ?? entry.reason ?? entry.concern),
      parsed_action: first(entry.recommended_action ?? entry.action),
      raw_ai_text: raw,
    }
  };
});

const items = $input.all();

function clean(v, fallback = '—') {
  if (v === undefined || v === null) return fallback;
  const s = String(v).trim();
  return s === '' ? fallback : s;
}

function pick(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

return [{
  json: {
    message: items.map(item => {
      const j = item.json;

      const company = pick(j.company_name, j.company_id);
      const why = pick(j.parsed_reason, j.why_today, j.parsed_priority, j.raw_ai_text);
      const action = pick(j.parsed_action, j.recommended_action);

      return `📋 Rank: ${clean(j.priority_rank)} (score ${clean(j.overall_priority_score)})
Company: ${clean(company)}
Email sentiment: ${clean(j.email_sentiment)}
Why today: ${clean(why)}
Action: ${clean(action)}`;
    }).join('\n\n---\n\n')
  }
}];

const items = $input.all();

function num(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

// Renewal proximity: closer renewal = higher score. Overdue counts as max urgency.
function renewalProximityScore(dateStr) {
  if (!dateStr) return 0;
  const renewal = new Date(dateStr);
  if (isNaN(renewal.getTime())) return 0;
  const now = new Date();
  const daysToRenewal = Math.ceil((renewal - now) / 86400000);
  if (daysToRenewal <= 30) return 100;
  if (daysToRenewal <= 60) return 75;
  if (daysToRenewal <= 90) return 50;
  if (daysToRenewal <= 180) return 25;
  return 5;
}

// Health / risk tier: worse health = higher score.
function healthRiskScore(status) {
  const v = String(status || '').toLowerCase().replace(/[^a-z]/g, '');
  const map = { atrisk: 100, critical: 100, watch: 55, monitor: 55, healthy: 10, good: 10, unknown: 35 };
  return map[v] ?? 35;
}

// Open escalations: ticket volume + highest severity.
function escalationScore(count, severity) {
  const sevMap = { LOW: 10, MEDIUM: 30, HIGH: 60, URGENT: 100, NONE: 0 };
  const sevScore = sevMap[String(severity || 'NONE').toUpperCase()] ?? 0;
  const countBonus = Math.min(num(count) * 8, 40);
  return Math.min(sevScore + countBonus, 100);
}

// Expansion signal: rising usage = upsell opportunity.
// NOTE: verify 'usage_trend' matches your actual HubSpot property values.
function expansionScore(trend) {
  const v = String(trend || '').toLowerCase();
  if (v.includes('increas') || v.includes('grow') || v.includes('expand')) return 80;
  if (v.includes('stable') || v.includes('flat')) return 20;
  return 0;
}

return items.map(item => {
  const j = item.json;
  return {
    json: {
      ...j,
      renewal_proximity_score: renewalProximityScore(j.renewal_date),
      health_risk_score: healthRiskScore(j.health_status),
      escalation_score: escalationScore(j.open_ticket_count, j.highest_severity),
      expansion_score: expansionScore(j.usage_trend),
    }
  };
});

const items = $input.all();

const urgencyRank = { high: 3, medium: 2, low: 1 };

const byCompany = {};

for (const item of items) {
  const j = item.json;
  const companyId = String(j.company_id || '').trim();
  if (!companyId) continue; // no matching account for this email — drop it

  const rank = urgencyRank[String(j.email_urgency_flag || '').toLowerCase()] || 0;
  const existing = byCompany[companyId];

  if (!existing) {
    byCompany[companyId] = { ...j, company_id: companyId, _rank: rank };
    continue;
  }

  const existingDate = new Date(existing.date || 0).getTime();
  const currentDate = new Date(j.date || 0).getTime();

  if (rank > existing._rank || (rank === existing._rank && currentDate > existingDate)) {
    byCompany[companyId] = { ...j, company_id: companyId, _rank: rank };
  }
}

return Object.values(byCompany).map(j => {
  const { _rank, ...rest } = j;
  return { json: rest };
});

